            .split => { try re.closure(cur, vis, alloc, nd.out1, pos, input); try re.closure(cur, vis, alloc, nd.out2, pos, input); },
            .save  => try re.closure(cur, vis, alloc, nd.out1, pos, input),
            .bol   => {
