    var i: usize = 0;
    while (i < input.len) {
        if (re.matchAt(input, i, re.flags.lazy_match) catch null) |e| {
            out.append(std.heap.page_allocator, input[i..e]) catch @panic("OOM");
            i = if (e > i) e else i + 1;
        } else i += 1;
