fn _hex_encode(bytes: []const u8) []const u8 {
    const _hx = "0123456789abcdef";
    var out = _allocator.alloc(u8, bytes.len * 2) catch return "";
    for (bytes, 0..) |b, i| { out[i*2] = _hx[b >> 4]; out[i*2+1] = _hx[b & 0xf]; }
